// noinspection JSUnresolvedReference,JSUnusedGlobalSymbols,ES6ConvertVarToLetConst

// ==================================================================

var Thread = Java.type("java.lang.Thread");
var Runnable = Java.type("java.lang.Runnable");
var HashMap = Java.type("java.util.HashMap");
var PlayParam = Java.type("com.brekeke.tel.PlayParam");

// ==================================================================

var languages = {
    "日本語": "ja",
    "英語": "en",
    "中国語": "zh",
    "韓国語": "ko",
}

var speechRecognitionFlags = {
    "検出しない": 0,
    "音声開始前から検出": 1,
    "音声開始から検出": 2,
};

var engines = {
    "会話汎用": 0,
    "会話医療": 1,
    "入力汎用": 2,
    "入力医療": 3,
};

var types = {
    "テキスト": 0,
    "診療科": 1,
    "氏名": 2,
    "氏名カナ": 3,
    "数値": 4,
    "電話番号": 5,
    "日時": 6,
    "氏名エンジン": 7
}

// ==================================================================

var getProperty = function(key, defVal) {
    var value = $runner.getProperty(key);
    if (!value || value === "デフォルト") {
        value = $runner.getProperty(".amivoice." + key);
    }
    return value ? value : defVal;
}

var getLanguage = function(key) {
    var language = getProperty(key, "");
    if (language) {
        return languages[language];
    }
    return $ivr.getLanguage();
}

var findSubModule = function(name) {
    var module = $runner.getCurrentModule();
    if (module) {
        for (var i = 0; i < module.subs.size(); i++) {
            var submod = module.subs.get(i);
            if (submod.label && submod.label.startsWith(name)) {
                return i + 1;
            }
        }
    }
    return 0;
}

// ==================================================================

var params = new HashMap();
params.put("from", $ivr.getOtherNumber());
params.put("to", $ivr.getMyNumber());
params.put("call_id", $ivr.getRID());
params.put("language", getLanguage("language"));
params.put("uri", getProperty("uri", ""));
params.put("engine", engines[getProperty("engine", "会話汎用")]);
params.put("keep_filter_token", $runner.getProperty("keep_filter_token").equalsIgnoreCase("yes"));
params.put("silent_detection_ms", getProperty("silent_detection_ms", 1500));
params.put("timeout_ms", getProperty("timeout_ms", 30000));
params.put("profile_words", $runner.getProperty("profile_words"));
params.put("type", types[getProperty("type", "テキスト")]);
params.put("probability", getProperty("probability", 0.7));
params.put("save_log", $runner.getProperty("save_log").equalsIgnoreCase("yes"));
params.put("detection_flag", speechRecognitionFlags[getProperty("detection_flag", "音声開始前から検出")]);

// @debug
$runner.getLogger().debug(">>> Amivoice Property: " + params);

// ==================================================================

var detectionFlag = params.get("detection_flag");
var assi = $ivr.startAudioPlugin("amivoice", params, detectionFlag);

// ==================================================================

if (assi) {
    var playParam = new PlayParam();
    playParam.setFileName($ivr.getEx().ivr.userinfo.getPrivateOrSystemPlayFileName("ja", "recstart"));
    $ivr.getEx().ivr.ply.playDtmfIgnore(playParam);

    var results;
    var error;

    var runner = new Runnable({
        run: function() {
            try {
                var stopPlaying = false;
                while (assi.isRunning()) {
                    assi.waitResult();

                    if (!stopPlaying) {
                        $ivr.stopPlaying();
                        stopPlaying = true;
                    }
                    results = assi.obj.get("transcribe.data");

                    if (results) {
                        $ivr.stop();
                        $runner.getLogger().info(">>> Transcribed data: " + JSON.stringify(results));
                        break;
                    }
                }
            } catch (e) {
                error = e;
                $runner.getLogger().error(e);
                if (e instanceof java.lang.InterruptedException) {
                    Thread.currentThread().interrupt();
                }
            } finally {
                $runner.getLogger().info(">>> Transcribed finished");
                assi.stop();
            }
        }
    });

    var worker = new Thread(runner);
    worker.start();

    var timeoutMs = getProperty("timeout_ms", 30000);
    worker.join(timeoutMs);

    assi.stop();

    if (worker.isAlive()) {
        $runner.setResult("TIMEOUT");
    } else if (error || (results && results.error)) {
        $runner.setResult("ERROR");
    } else {
        if (results && results.transcribe) {
            if (params.get("type") === 0) {
                // 音声タイプがテキストの時、RAG検索が必要なら実行.
                try {
                    var rag = findSubModule("rag-");
                    if (rag > 0) {
                        $runner.set("transcribe.data", JSON.stringify(results));
                        $runner.execSub(rag);
                        var ragData = $runner.get("transcribe.rag");
                        if (ragData) {
                            var ragJson = JSON.parse(ragData);
                            results.data = ragJson.word;
                            $runner.getLogger().info(">>> RAG module: " + JSON.stringify(results));
                        }
                    }
                } finally {
                    $runner.remove("transcribe.data");
                    $runner.remove("transcribe.rag");
                }
            }
            // 結果をDBに保存する必要がある場合は実行.
            try {
                var save = findSubModule("save-");
                if (save > 0) {
                    $runner.set("transcribe.save", JSON.stringify(results));
                    $runner.execSub(save);
                }
            } finally {
                $runner.remove("transcribe.save");
            }
            // 結果を設定.
            $runner.setResult(results.data ? results.data : results.transcribe);
        } else {
            // 結果なしの時.
            $runner.setResult("NO_RESULT");
        }
    }
} else {
    $runner.setResult("ERROR");
}

$runner.getLogger().info(">>> Save to database - ENHANCED VERSION WITH CALL-LEVEL CONNECTION MANAGEMENT");
var contextName = $runner.getProperty("contextName");
var contextDisplayType = $runner.getProperty("contextDisplayType");
var seqNumber = $runner.get("seq") ? $runner.get("seq") : 1; 

function parseTranscribeData() {
    var data = $runner.get("transcribe.save");
    if (!data) {
      $runner.getLogger().warn("No transcribe data found");
      return null;
    }
    
    try {
      return JSON.parse(data);
    } catch (e) {
      $runner.getLogger().error("Invalid JSON data: " + e);
      return null;
    }
  }
  
function getContextData(jsonObj) {
  if (!contextName || !jsonObj || jsonObj.actor === "AI") return null;

  var contextValue = jsonObj.data ? jsonObj.data : jsonObj.transcribe;

  // Save the department name to the runner object if the display type is DEPARTMENT, for use with the check-frame-time module.
  if(contextDisplayType === "DEPARTMENT") {
    $runner.setObject("department-name", contextValue);
  } else if (contextDisplayType === "PHONE_NUMBER") {
    contextValue = contextValue.replace(/\D/g, ''); // Remove non-digit characters for phone numbers
  }

  return {
    contextName:contextName,
    displayType:contextDisplayType,
    value:contextValue
  };
}

function parseTimestampToMillis(dateTime) {
  var millisecond = $ivr.exec("save2db", "parseTimestamp", dateTime);
  var callTransferTimeKey = "transfer_time_" + $ivr.getRID();
  var transferTime = $runner.getObject(callTransferTimeKey);

  // Subtract the transfer time from the total time in milliseconds, because sound contains no transfer.
  if (transferTime) {
    millisecond = millisecond - transferTime;
  }
  return millisecond;
}

function getUtteranceData(jsonObj, seqNumber) {
  if (!jsonObj) return null;

  var utteranceValue = jsonObj.transcribe ? jsonObj.transcribe : "";
  var messageType = jsonObj.actor === "AI" ? 0 : 1;
  var startMsec = 0;
  var endMsec = 0;
  
  if (jsonObj.start_ts) {
    startMsec = parseTimestampToMillis(jsonObj.start_ts);
  }
  
  if (jsonObj.end_ts) {
    endMsec = parseTimestampToMillis(jsonObj.end_ts);
  }

  return {
    seq:seqNumber,
    messageType:messageType,
    text:utteranceValue,
    utteranceType:"MESSAGE",
    startMsec:startMsec,
    endMsec:endMsec
  };
}

// ==================================================================
// MAIN EXECUTION WITH COMPREHENSIVE ERROR HANDLING AND MONITORING
var jsonObj = null;
var operationSuccess = false;

// Start timing
var startTime = new Date().getTime();
$runner.getLogger().info(">>> Starting ENHANCED database save operation");

try {
  // Step 1: Parse data
  jsonObj = parseTranscribeData();
  if (!jsonObj) {
    $runner.getLogger().warn("No valid transcribe data to save");
    return;
  }

  // Step 2: Prepare data for saving
  var contextField = getContextData(jsonObj);
  var utterance = getUtteranceData(jsonObj, seqNumber);
  if (!contextField && !utterance) {
    $runner.getLogger().warn("No context or utterance data to save");
    return;
  }

  // Step 3: Execute database operation with monitoring
  var saveRequestData = {
    contextField:contextField,
    utterance:utterance
  };
  operationSuccess = $ivr.exec("save2db", "save", JSON.stringify(saveRequestData));

  if (operationSuccess) {
    // Update sequence number only on success
    $runner.set("seq", (seqNumber + 1));
    
    var totalTime = new Date().getTime() - startTime;
    $runner.getLogger().info("DATABASE SAVE COMPLETED SUCCESSFULLY! Total time: " + totalTime + "ms");
  } else {
    $runner.getLogger().error("Database operation failed - sequence number not updated");
  }
  
} catch (e) {
  var errorTime = new Date().getTime() - startTime;
  $runner.getLogger().error("CRITICAL ERROR in database save operation after " + errorTime + "ms: " + e);
  
  // Log detailed error information
  if (e.stack) {
    $runner.getLogger().error("Error stack: " + e.stack);
  }
} finally {
  // NOTE: Connection is managed at call level - no need to close here
  // The call cleanup monitor will handle connection cleanup when call ends
  
  // Final timing and status
  var finalTotalTime = new Date().getTime() - startTime;
  var status = operationSuccess ? "SUCCESS" : "FAILED";
  $runner.getLogger().info(">>> Database save operation " + status + ". Total execution time: " + finalTotalTime + "ms");
  
  $runner.setModuleResult($runner.getLastModuleName(), jsonObj.data ? jsonObj.data : jsonObj.transcribe);
}

$runner.getLogger().info(">>> Save to database - ENHANCED VERSION WITH CALL-LEVEL CONNECTION MANAGEMENT");
  
function getContextData(statusId, smsFlag) {
  if (!statusId && !smsFlag) return null;

  var contexts = [];
  if (statusId) {
    contexts.push({
      contextName: "status",
      displayType: "STATUS",
      value: statusId
    });
  }

  if (smsFlag) {
    contexts.push({
      contextName: "smsFlag",
      displayType: "TEXT",
      value: smsFlag
    });
  }
  return contexts;
}

// ==================================================================
// MAIN EXECUTION WITH COMPREHENSIVE ERROR HANDLING AND MONITORING
var operationSuccess = false;

// Start timing
var startTime = new Date().getTime();
$runner.getLogger().info(">>> Starting ENHANCED database save operation");

try {
  // Step 1: Get data
  var statusId = $runner.getProperty("status");
  var smsFlag = $runner.getProperty("smsFlag");

  // Step 2: Prepare data
  var contextFields = getContextData(statusId, smsFlag);
  if (!contextFields || contextFields.length === 0) {
    $runner.getLogger().warn("No context data to save");
    return;
  }

  // Step 3: Execute database operation with monitoring
  var saveRequestData = {contextFields: contextFields};
  operationSuccess = $ivr.exec("save2db", "updateContextFields", JSON.stringify(saveRequestData));
  
  if (operationSuccess) {
    var totalTime = new Date().getTime() - startTime;
    $runner.getLogger().info("DATABASE SAVE COMPLETED SUCCESSFULLY! Total time: " + totalTime + "ms");
  } else {
    $runner.getLogger().error("Database operation failed");
  }
  
} catch (e) {
  var errorTime = new Date().getTime() - startTime;
  $runner.getLogger().error("CRITICAL ERROR in database save operation after " + errorTime + "ms: " + e);
  
  // Log detailed error information
  if (e.stack) {
    $runner.getLogger().error("Error stack: " + e.stack);
  }
  
} finally {
  // NOTE: Connection is managed at call level - no need to close here
  // The call cleanup monitor will handle connection cleanup when call ends
  
  // Final timing and status
  var finalTotalTime = new Date().getTime() - startTime;
  var status = operationSuccess ? "SUCCESS" : "FAILED";
  $runner.getLogger().info(">>> Database save operation " + status + ". Total execution time: " + finalTotalTime + "ms");
}

// ==================================================================

var URI = Java.type("java.net.URI");
var HttpClient = Java.type("java.net.http.HttpClient");
var HttpRequest = Java.type("java.net.http.HttpRequest");
var HttpResponse = Java.type("java.net.http.HttpResponse");
var Duration = Java.type("java.time.Duration");

// ==================================================================

var getProperty = function(key, defVal) {
    var value = $runner.getProperty(key);
    if (!value) {
        value = $runner.getProperty(".context.settings." + key);
    }
    return value ? value : defVal;
}

function isJsonArray(field) {
    try {
        if (typeof field !== "string") {
            return false;
        }
        
        var parsed = JSON.parse(field);
        return Array.isArray(parsed);
        
    } catch (e) {
        return false;
    }
}
// ==================================================================
var callId = $ivr.getRID();
var deployTo = $ivr.getMyNumber();
var officeId = $runner.getProperty(".office_id");
var tenantId = $ivr.getTenant();
// Check if fields is JSON array
var fields = $runner.getProperty("fields");
var isArray = isJsonArray(fields);
if (!isArray) {
    $runner.getLogger().error("[" + deployTo + "] " + "[" + callId + "] " +"Fields is not a JSON array");
    return;
}

// Parse fields
var jsonObj = JSON.parse(fields);
var url = getProperty("url", "");
$runner.getLogger().info("saveContextModel2DB " + url);
var connectTimeout = getProperty("connect_timeout", 2);
var requestTimeout = getProperty("request_timeout", 3);

// ==================================================================
var reqBody = {
    "tenantId": tenantId,
    "deployTo": deployTo,
    "officeId": officeId,
    "fields": jsonObj
}

var client = HttpClient.newBuilder()
    .connectTimeout(Duration.ofSeconds(connectTimeout))
    .build();

var req = HttpRequest.newBuilder()
    .uri(URI.create(url))
    .timeout(Duration.ofSeconds(requestTimeout))
    .header("Content-Type", "application/json")
    .POST(HttpRequest.BodyPublishers.ofString(JSON.stringify(reqBody)))
    .build();

$runner.getLogger().info("[" + deployTo + "] " + "[" + callId + "] " + "send request to " + url + " with body: " + JSON.stringify(reqBody));
client.send(req, HttpResponse.BodyHandlers.ofString());

// ==========================================================================
// functions
function getContextValue() {
  var data = $runner.getProperty("contextValue");
  if(!data) return null;

  return $ivr.exec("system-variable", "replaceTemplateVariables", data);
}

// ==========================================================================
// main
var contextName = $runner.getProperty("contextName");
var contextDisplayType = $runner.getProperty("contextDisplayType");
var contextValue = getContextValue();

if(!contextName || !contextDisplayType || !contextValue) {
  $runner.getLogger().info("[saveContext2DB] invalid input data");
  return;
}

var contextField = {
  contextName:contextName,
  displayType:contextDisplayType,
  value:contextValue
};

var saveRequestData = JSON.stringify({
  contextField:contextField
});

$runner.getLogger().info("[saveContext2DB] start save context " + saveRequestData);
try {
  $ivr.exec("save2db", "save", saveRequestData);
  $runner.setResult(contextValue);
} catch (e) {
  $runner.getLogger().error("[saveContext2DB][" + $ivr.getRID() + "] Error in execution: " + e);
  $runner.setResult(null);
}

var key = $runner.getProperty("key");
var nodeName = $runner.getProperty("nodeName");
var nodeValue = $runner.getModuleResult(nodeName);
$runner.getLogger().info("[" + $ivr.getRID() + "]" + "[saveData2Session] with key=" + key + ",value=" + nodeValue + "from node " + nodeName);
if(nodeValue) {
 $runner.setObject(key, nodeValue);
 $runner.setResult("SUCCESS");
} else {
 $runner.setResult("FAILED");
}

var key = $runner.getProperty("key");
var value = $runner.getObject(key);
$runner.getLogger().info("[" + $ivr.getRID() + "]" + "[getDataFromSession]  key=" + key + ", value=" + value);
$runner.setResult(value ? value : "NO_RESULT");

// noinspection JSUnresolvedReference,JSUnusedGlobalSymbols

// ==================================================================
// Import necessary Java classes
var URL = Java.type("java.net.URL");
var HttpURLConnection = Java.type("java.net.HttpURLConnection");
var JavaDate = Java.type("java.util.Date");
var SimpleDateFormat = Java.type("java.text.SimpleDateFormat");
var HttpC = Java.type("com.brekeke.web.HttpC");
var JSONObject = Java.type("org.json.JSONObject");

// ==================================================================
// Function to get properties from multiple sources
var getProperty = function(key, defVal) {
    var value = $runner.getProperty(key);
    if (!value) {
        // Log a warning if the key is not set
        $runner.getLogger().warn("Property '" + key + "' is not set. Using default value: " + defVal);
    }
    return value ? value : defVal;
}

// ==================================================================
// Set default return value
var ret = "false";
var retError = "ERROR";

// Get settings from Flow Designer
var host = getProperty(".acceptance_times.url", "");
var officeId = getProperty(".office_id", "");
var deployTo = $ivr.getMyNumber();
var tenantId = $ivr.getTenant();
var callId = $ivr.getRID();

// Create a log prefix to avoid duplication
var logPrefix = "[" + tenantId + "][" + officeId + "][" + deployTo + "][" + callId + "] ";

try {
    // Validate host URL
    if (!host || host === "") {
        $ivr.getLogger().error(logPrefix + "Acceptance times URL is not configured.");
        $runner.setResult(retError);
        return;
    }

    var dateFormat = new SimpleDateFormat("yyyyMMddHHmm");
    var formattedTime = dateFormat.format(new JavaDate());

    // Create API URL
    var apiUrl = host + "?tenantId="+tenantId+"&officeId=" +officeId+"&deployTo=" + deployTo + "&checkTime=" + formattedTime;
    $ivr.getLogger().info(logPrefix + "Calling API URL: " + apiUrl);

    // Call API using HttpC
    var httpc = new HttpC();
    var res = httpc.getS(new URL(apiUrl), null);

    // Log results
    $ivr.getLogger().info(logPrefix + "HTTP Status: " + res.responseCode);
    $ivr.getLogger().info(logPrefix + "Response Body: " + res.body);

    // Check response code early
    if (res.responseCode !== 200) {
        $ivr.getLogger().warn(logPrefix + "API returned non-200 status: " + res.responseCode);
        $ivr.getLogger().error(logPrefix + "API error response: " + res.body);
        $runner.setResult(retError);
        return;
    }

    // Parse JSON response
    var jsonResponse = new JSONObject(res.body);

    // Check for acceptable field early
    if (!jsonResponse.has("acceptable")) {
        $ivr.getLogger().warn(logPrefix + "Field 'acceptable' not found in API response.");
        $runner.setResult(retError);
        return;
    }

    var acceptable = jsonResponse.getBoolean("acceptable");
    $ivr.getLogger().info(logPrefix + "acceptable: " + acceptable);

    // If acceptable, return early with "true"
    if (acceptable) {
        ret = "true";
        $runner.setResult(ret);
        return;
    }

    // If not acceptable, check for guidance field
    if (!jsonResponse.has("guidance")) {
        $ivr.getLogger().warn(logPrefix + "Field 'guidance' not found in successful API response when acceptable is false.");
        $runner.setResult(retError);
        return;
    }

    var guidanceMessage = jsonResponse.getString("guidance");
    $ivr.getLogger().info(logPrefix + "Found guidance message when acceptable=false: " + guidanceMessage);

    // Check if guidance message is empty
    if (!guidanceMessage || (typeof guidanceMessage === "string" && guidanceMessage.trim() === "")) {
        $ivr.getLogger().warn(logPrefix + "Guidance message is empty, skipping TTS and DB save.");
        $runner.setResult(ret);
        return;
    }

    // Play TTS
    var startTime = new Date();
    $ivr.play("{tts_g:" + guidanceMessage + "}");
    var endTime = new Date();

    // Save to DB
    try {
        var seqNumber = $runner.get("seq") ? $runner.get("seq") : 1;
        $ivr.getLogger().info(logPrefix + "TTS/save text=" + guidanceMessage);
        var utterance = {
            seq: seqNumber,
            messageType: 0,
            text: guidanceMessage,
            utteranceType: "MESSAGE",
            startMsec: $ivr.exec("save2db", "parseTimestamp", startTime.toISOString()),
            endMsec: $ivr.exec("save2db", "parseTimestamp", endTime.toISOString())
        };
        var operationSuccess = $ivr.exec("save2db", "save", JSON.stringify({utterance: utterance}));
        if (!operationSuccess) {
            $ivr.getLogger().error(logPrefix + "Failed to save TTS data to database.");
        } else {
            $runner.set("seq", (seqNumber + 1));
            $ivr.getLogger().info(logPrefix + "Successfully saved TTS data to database and updated seq number to " + (seqNumber + 1));
        }
    } catch (error) {
        $ivr.getLogger().error(logPrefix + "Failed to save TTS data to database: " + error);
    }
} catch (e) {
    $ivr.getLogger().error(logPrefix + "Error during API call: " + e.message);
    ret = retError;
} finally {
    // No resource cleanup is necessary for HttpC
}

$runner.setResult(ret);

// noinspection JSUnresolvedReference,JSUnusedGlobalSymbols

// ==================================================================
// Import necessary Java classes for the HTTP Client
var URI = Java.type("java.net.URI");
var HttpClient = Java.type("java.net.http.HttpClient");
var HttpRequest = Java.type("java.net.http.HttpRequest");
var HttpResponse = Java.type("java.net.http.HttpResponse");
var Duration = Java.type("java.time.Duration");
var JSONObject = Java.type("org.json.JSONObject");

// ==================================================================
// Function to get properties from multiple sources
var getProperty = function(key, defVal) {
    var value = $runner.getProperty(key);
    if (!value) {
        // Log a warning if the key is not set
        $runner.getLogger().warn("Property '" + key + "' is not set. Using default value: " + defVal);
    }
    return value || defVal;
}

// Function to get clean text from SSML string (removes SSML tags only)
// Note: Input should already be normalized and trimmed
var getPlainTextFromSSML = function(ssml) {
    if (!ssml) {
        return "";
    }
    // Simple regex to strip SSML tags (no trim needed as input is already normalized)
    return ssml.replace(/<[^>]*>/g, "");
}

// Function to normalize SSML for playback by removing newlines
var normalizeSSMLForPlayback = function(ssml) {
    if (!ssml) {
        return "";
    }
    // Remove newlines, normalize multiple spaces to single space, and trim
    return ssml.replace(/\r\n/g, " ").replace(/\n/g, " ").replace(/\r/g, " ").replace(/\s+/g, " ").trim();
}

// Function to save TTS utterance to database
var saveTTSToDatabase = function(normalizedSSML, startTime, endTime, logPrefix) {
    try {
        var transcribeText = getPlainTextFromSSML(normalizedSSML);
        var seqNumber = $runner.get("seq") ? $runner.get("seq") : 1;
        $runner.getLogger().info(logPrefix + "TTS/save text=" + transcribeText);
        var utterance = {
            seq: seqNumber,
            messageType: 0,
            text: transcribeText,
            utteranceType: "MESSAGE",
            startMsec: $ivr.exec("save2db", "parseTimestamp", startTime.toISOString()),
            endMsec: $ivr.exec("save2db", "parseTimestamp", endTime.toISOString())
        };
        var operationSuccess = $ivr.exec("save2db", "save", JSON.stringify({utterance: utterance}));
        if (!operationSuccess) {
            $runner.getLogger().error(logPrefix + "Failed to save TTS data to database.");
        } else {
            $runner.set("seq", (seqNumber + 1));
            $runner.getLogger().info(logPrefix + "Successfully saved TTS data to database and updated seq number to " + (seqNumber + 1));
        }
    } catch (error) {
        $runner.getLogger().error(logPrefix + "Failed to save TTS data to database: " + error);
    }
}

// ==================================================================
// Constants for module result values
var RESULT_ERROR = 'ERROR';
var RESULT_NO_RESULT = 'NO_RESULT';

// ==================================================================

// Get configuration properties from the Flow Designer
var host = getProperty(".rag_ssml.url", "");
var tenantId = $ivr.getTenant();
var officeId = getProperty(".office_id", "");
var deployTo = $ivr.getMyNumber();
var callId = $ivr.getRID();
var saveToDB = getProperty("saveToDB", "No").equalsIgnoreCase("Yes");

// Create a common log prefix to avoid duplication
var logPrefix = "[" + tenantId + "][" + officeId + "][" + deployTo + "][" + callId + "] ";

// Initialize return value
var ret = "";

try {
    // Check if RAG is enabled. If not, set NO_RESULT.
    var useRag = getProperty("use_rag", "Yes");
    if (useRag !== "Yes") {
        $runner.getLogger().info(logPrefix + "RAG is not enabled. Returning NO_RESULT.");
        $runner.setResult(RESULT_NO_RESULT);
        return;
    }
    // Get text from the previous Speech to Text module
    // Note: The STT module name must be defined in the 'module' property of this node.
    var moduleName = getProperty("module", "");
    var userInputText = $runner.getModuleResult(moduleName);
    if (!userInputText) {
        $runner.getLogger().warn(logPrefix + "No recognized text. Exiting.");
        $runner.setResult(RESULT_ERROR);
        return;
    }
    $runner.getLogger().info(logPrefix + "Recognized text: " + userInputText);

    // Validate host URL
    if (!host || host === "") {
        $runner.getLogger().error(logPrefix + "RAG SSML URL is not configured.");
        $runner.setResult(RESULT_ERROR);
        return;
    }

    // Get distance parameter for RAG similarity search
    var distance = parseFloat(getProperty("distance", "0.3"));
    $runner.getLogger().info(logPrefix + "distance: " + distance);
    $runner.getLogger().info(logPrefix + "Calling API URL: " + host);

    // Create JSON payload object according to the RagSsmlRequest structure
    var requestPayload = new JSONObject();
    requestPayload.put("tenantId", tenantId);
    requestPayload.put("officeId", officeId);
    requestPayload.put("deployTo", deployTo);
    requestPayload.put("text", userInputText);
    requestPayload.put("distance", distance);

    $runner.getLogger().debug(logPrefix + "Request Payload: " + requestPayload.toString());

    // Make the HTTP POST call using HttpClient
    var client = HttpClient.newBuilder()
        .connectTimeout(Duration.ofSeconds(10))
        .build();

    var req = HttpRequest.newBuilder()
        .uri(URI.create(host))
        .header("Content-Type", "application/json")
        .timeout(Duration.ofSeconds(10))
        .POST(HttpRequest.BodyPublishers.ofString(requestPayload.toString()))
        .build();

    var res = client.send(req, HttpResponse.BodyHandlers.ofString());

    var responseCode = res.statusCode();
    $runner.getLogger().info(logPrefix + "API response code: " + responseCode);

    if (responseCode !== 200) {
        $runner.getLogger().error(logPrefix + "API call failed. Error code: " + responseCode);
        $runner.getLogger().error(logPrefix + "Error response: " + res.body());
        $runner.setResult(RESULT_ERROR);
        return;
    }

    var resBody = res.body();
    $runner.getLogger().debug(logPrefix + "Raw JSON response from API: " + resBody);

    var jsonResponse = new JSONObject(resBody);

    // Handle error response (only if error field has actual value)
    if (jsonResponse.has("error")) {
        var errorMessage = jsonResponse.getString("error");
        if (errorMessage && errorMessage !== "" && errorMessage !== "null") {
            $runner.getLogger().error(logPrefix + "API error: " + errorMessage);
            $runner.setResult(RESULT_ERROR);
            return;
        }
    }

    // Handle message response
    if (!jsonResponse.has("message")) {
        $runner.getLogger().error(logPrefix + "API response does not contain 'message' or 'error' fields.");
        $runner.setResult(RESULT_ERROR);
        return;
    }

    var ssmlResponse = jsonResponse.getString("message");
    $runner.getLogger().info(logPrefix + "Received SSML string: " + ssmlResponse);

    // Check if message is null
    if (ssmlResponse === null || ssmlResponse === "null") {
        $runner.getLogger().error(logPrefix + "Null 'message' response. Returning ERROR.");
        $runner.setResult(RESULT_ERROR);
        return;
    }

    // Check if message is empty
    if (ssmlResponse === "") {
        $runner.getLogger().info(logPrefix + "Empty 'message' response. Returning NO_RESULT.");
        $runner.setResult(RESULT_NO_RESULT);
        return;
    }

    // Normalize SSML to remove newlines that might cause parsing issues
    var normalizedSSML = normalizeSSMLForPlayback(ssmlResponse);
    $runner.getLogger().debug(logPrefix + "Normalized SSML for playback: " + normalizedSSML);

    // If normalized SSML is empty after normalization, set result without playing or saving
    if (!normalizedSSML || normalizedSSML === "") {
        $runner.getLogger().warn(logPrefix + "Normalized SSML is empty. Returning NO_RESULT.");
        $runner.setResult(RESULT_NO_RESULT);
        return;
    }

    // Play TTS
    var startTime = new Date();
    $ivr.play("{tts_g:" + normalizedSSML + "}");
    var endTime = new Date();
    ret = normalizedSSML;

    // Save to DB if enabled (isolated error handling - save failure should not affect main flow)
    if (saveToDB) {
        saveTTSToDatabase(normalizedSSML, startTime, endTime, logPrefix);
    }
} catch (e) {
    $runner.getLogger().error(logPrefix + "Error in script: " + e.message);
    ret = RESULT_ERROR;
}

// Set the module result to control the flow
$runner.getLogger().info(logPrefix + "Final result before setResult: " + ret);
$runner.setResult(ret);

