// Import necessary Java classes for the HTTP Client
var URI = Java.type("java.net.URI");
var HttpClient = Java.type("java.net.http.HttpClient");
var HttpRequest = Java.type("java.net.http.HttpRequest");
var HttpResponse = Java.type("java.net.http.HttpResponse");
var Duration = Java.type("java.time.Duration");
var JSONObject = Java.type("org.json.JSONObject");
var HttpTimeoutException = Java.type("java.net.http.HttpTimeoutException");
var SocketTimeoutException = Java.type("java.net.SocketTimeoutException");

// ==================================================================
// Function to get properties from multiple sources
var getProperty = function(key, defVal) {
    var value = $runner.getProperty(key);
    if (!value) {
        // Log a warning if the key is not set
        $runner.getLogger().warn("Property '" + key + "' is not set. Using default value: " + defVal);
    }
    return value ? value : defVal;
}

/**
 * Validates if the functionCall string is a valid JSON.
 * @param {string} functionCall - The functionCall string to validate.
 * @returns {boolean} - True if valid, false otherwise.
 */
var isValidFunctionCallJSON = function(functionCall) {
    if (!functionCall || functionCall.trim() === "") {
        return true; // Empty is considered valid as it's optional
    }
    try {
        new JSONObject(functionCall);
        return true;
    } catch (e) {
        $runner.getLogger().error(logPrefix + "Invalid JSON format for functionCall: " + e.message);
        return false;
    }
};

/**
 * prepares the request payload for the OpenAI API.
 * @returns {JSONObject} The request payload for the OpenAI API.
 */
var getRequestPayload = function() {
    // --- Get input data ---
    // Get text from the previous Speech to Text module
    // Note: The STT module name must be defined in the 'module' property of this node.
    var moduleName = getProperty("module", "");
    var userInputText = $runner.getModuleResult(moduleName);

    if (userInputText === null || userInputText === "") {
        $runner.getLogger().warn(logPrefix + "No recognized text. Exiting.");
        return null;
    }
    $runner.getLogger().info(logPrefix + "Recognized text: " + userInputText);
    
    var prompt = getProperty("prompt", "");
    $runner.getLogger().info(logPrefix + "prompt: " + prompt);
    // Add current date to prompt if prompt has data
    if (prompt && prompt !== "") {
        var today = new Date();
        var year = today.getFullYear();
        var month = today.getMonth() + 1; // getMonth() returns 0-11
        var day = today.getDate();
        var currentDate = year + "年" + month + "月" + day + "日";
        prompt = "今日は" + currentDate + "\n" + prompt;
    }

    var functionCall = getProperty("functionCall", "");
    $runner.getLogger().info(logPrefix + "functionCall: " + functionCall);

    if (!isValidFunctionCallJSON(functionCall)) {
        $runner.getLogger().error(logPrefix + "Invalid JSON format for functionCall.");
        return null; // Stop processing if JSON is invalid
    }

    // Configure API and payload
    var apiUrl = host;
    $runner.getLogger().info(logPrefix + "Calling API URL: " + apiUrl);

    // Create JSON payload object according to the openAiRequest structure
    var requestPayload = new JSONObject();
	requestPayload.put("tenantId", tenantId);
	requestPayload.put("officeId", officeId);
    requestPayload.put("deployTo", deployTo);
	requestPayload.put("prompt", prompt);
    requestPayload.put("text", userInputText);
    requestPayload.put("functionCall", functionCall);
    return requestPayload;
}

/**
 * Makes an HTTP POST request to the OpenAI API
 * @param {string} apiUrl - The API URL to call
 * @param {string} requestPayload - The JSON payload to send
 * @returns {HttpResponse} The HTTP response object
 */
var makeHttpRequest = function(apiUrl, requestPayload) {
    var client = HttpClient.newBuilder()
        .connectTimeout(Duration.ofSeconds(10))
        .build();

    var req = HttpRequest.newBuilder()
        .uri(URI.create(apiUrl))
        .header("Content-Type", "application/json")
        .timeout(Duration.ofSeconds(10))
        .POST(HttpRequest.BodyPublishers.ofString(requestPayload))
        .build();

    return client.send(req, HttpResponse.BodyHandlers.ofString());
};

/**
 * Determines if an exception is a timeout-related exception
 * @param {Error} e - The thrown exception
 * @returns {boolean}
 */
var isTimeoutException = function(e) {
    try { if (e instanceof HttpTimeoutException) return true; } catch (_) {}
    try { if (e instanceof SocketTimeoutException) return true; } catch (_) {}
    var msg = (e && e.message) ? ("" + e.message).toLowerCase() : "";
    return msg.indexOf("timed out") >= 0 || msg.indexOf("timeout") >= 0;
};

/**
 * Processes a successful API response (status code 200)
 * @param {HttpResponse} response - The HTTP response object
 * @returns {string} The result to set for the module
 */
var processSuccessfulResponse = function(response) {
    var resBody = response.body();
    $runner.getLogger().debug(logPrefix + "Raw JSON response from API: " + resBody);

    var jsonResponse = new JSONObject(resBody);

    if (jsonResponse.has("generatedText")) {
        return handleGeneratedTextResponse(jsonResponse);
    } else if (jsonResponse.has("error")) {
        return handleErrorResponse(jsonResponse);
    } else {
        $runner.getLogger().error(logPrefix + "API response does not contain 'generatedText' or 'error' fields.");
        return "NO_RESULT";
    }
};

/**
 * Extracts the TTS content from the prompt.
 * @param {string} prompt - The prompt string to extract TTS content from.
 * @returns {string} The extracted TTS content or an empty string if not found.
 */
var extractTTSContent = function(prompt) {
  if(!prompt) {
    return "";
  }
  
  var match = prompt.match(/\{tts_g:([^}]*)\}/);
  if (!match) {
    return "";
  }
  var content = match[1];
  return content;
}

/**
 * Speaks the OpenAI response using the TTS prompt
 * @param {string} openAiResponse - The OpenAI response to prepare the TTS prompt for
 */
var speakOpenAiResponse = function(openAiResponse) {
    var promptTTS = getProperty("promptTTS", "");
    if (!promptTTS || promptTTS === "") {
        $runner.getLogger().error(logPrefix + "No TTS prompt found.");
        return null;
    }
    promptTTS = promptTTS.replaceAll("#data#", openAiResponse);
    var startTime = new Date();
    $ivr.play(promptTTS, false);
    var endTime = new Date();
    var seqNumber = $runner.get("seq") ? $runner.get("seq") : 1;
    $runner.set("seq", (seqNumber + 1));
    return {
        seq:seqNumber,
        messageType:0,
        text:extractTTSContent(promptTTS),
        utteranceType:"MESSAGE",
        startMsec:$ivr.exec("save2db", "parseTimestamp", startTime.toISOString()),
        endMsec:$ivr.exec("save2db", "parseTimestamp", endTime.toISOString())
    };
};

var prepareContextField = function(openAiResponse) {
    var contextName = getProperty("contextName", "");
    var contextDisplayType = getProperty("contextDisplayType", "");
    if (!contextName || contextName === "" || !contextDisplayType || contextDisplayType === "" || !openAiResponse || openAiResponse === "") {
        $runner.getLogger().error(logPrefix + "No context name or display type found.");
        return null;
    }

    return {
        contextName: contextName,
        displayType: contextDisplayType,
        value: openAiResponse
    }
};

/**
 * Saves the OpenAI response as a context field
 * @param {object} contextField - The context field object
 * @param {object} utterance - The utterance object
 */
var saveOpenAiResponseAsContextField = function(contextField, utterance) {
    if (!contextField && !utterance) {
        $runner.getLogger().error(logPrefix + "No context field and utterance found.");
        return;
    }

    var saveRequestData = {
        contextField:contextField,
        utterance:utterance
    };
    var operationSuccess = $ivr.exec("save2db", "save", JSON.stringify(saveRequestData));
    if (!operationSuccess) {
        $runner.getLogger().error(logPrefix + "Failed to save OpenAI response as context field.");
    }
    $runner.getLogger().info(logPrefix + "Successfully saved OpenAI response as context field.");
};

/**
 * Handles the generatedText field in API response
 * @param {JSONObject} jsonResponse - The parsed JSON response
 * @returns {string} The result to set for the module
 */
var handleGeneratedTextResponse = function(jsonResponse) {
    var openAiResponse = jsonResponse.getString("generatedText");
    $runner.getLogger().info(logPrefix + "Received generated text: " + openAiResponse);

    if (openAiResponse !== null && openAiResponse !== "") {
        var utterance = speakOpenAiResponse(openAiResponse);
        var contextField = prepareContextField(openAiResponse);
        saveOpenAiResponseAsContextField(contextField, utterance);
        return openAiResponse;
    } else {
        $runner.getLogger().error(logPrefix + "Empty 'generatedText' response.");
        return "NO_RESULT";
    }
};

/**
 * Handles error response from API
 * @param {JSONObject} jsonResponse - The parsed JSON response
 * @returns {string} The result to set for the module
 */
var handleErrorResponse = function(jsonResponse) {
    var errorMessage = jsonResponse.getString("error");
    $runner.getLogger().error(logPrefix + "API error: " + errorMessage);
    return "ERROR";
};

/**
 * Handles HTTP error responses (non-200 status codes)
 * @param {HttpResponse} response - The HTTP response object
 * @returns {string} The result to set for the module
 */
var handleHttpError = function(response) {
    var responseCode = response.statusCode();
    $runner.getLogger().error(logPrefix + "API call failed. Error code: " + responseCode);
    $runner.getLogger().error(logPrefix + "Error response: " + response.body());
    return "ERROR";
};

// ==================================================================

// Get configuration properties from the Flow Designer
var host = getProperty(".openAI_generate.url", "");
var officeId = getProperty(".office_id", "");
var deployTo = $ivr.getMyNumber();
var tenantId = $ivr.getTenant();
var callId = $ivr.getRID();

// Create a common log prefix to avoid duplication
var logPrefix = "[" + tenantId + "][" + officeId + "][" + deployTo + "][" + callId + "] ";

// Initialize return value
var ret = "";

try {
    var requestPayload = getRequestPayload();
    if (!requestPayload) {
        $runner.getLogger().error(logPrefix + "Failed to create request payload.");
        $runner.setResult("ERROR");
        return;
    }

    $runner.getLogger().debug(logPrefix + "Request Payload: " + requestPayload.toString());

    // Make HTTP request and process response
    var response = makeHttpRequest(host, requestPayload.toString());
    var responseCode = response.statusCode();
    $runner.getLogger().info(logPrefix + "API response code: " + responseCode);

    if (responseCode === 200) {
        ret = processSuccessfulResponse(response);
    } else {
        ret = handleHttpError(response);
    }

} catch (e) {
    if (isTimeoutException(e)) {
        ret = "TIMEOUT";
        $runner.getLogger().error(logPrefix + "Request timed out: " + e.message);
    } else {
        ret = "ERROR";
        $runner.getLogger().error(logPrefix + "Error in script: " + e.message);
    }
}

// Set the module result to control the flow
$runner.setResult(ret);

