function buildApiUrl(host, tenantId, officeId, deployTo, phoneNumber) {
    return host + "?tenantId=" + tenantId + "&officeId=" + officeId + "&deployTo=" + deployTo + "&phoneNumber=" + phoneNumber;
}

function parseKatakanaNameFromBody(body) {
    try {
        var json = new JSONJAVA(body);
        // Dùng optString để tránh throw nếu không có field
        return json.optString("nameKana", "");
    } catch (e) {
        return "";
    }
}

