// 1) Function gọi API để lấy katakana name theo phone
function fetchKatakanaNameByPhone(host, tenantId, officeId, deployTo, logPrefix, phoneNumber) {
    var httpc = new HttpC();
    var apiUrl = buildApiUrl(host, tenantId, officeId, deployTo, phoneNumber);
    $ivr.getLogger().info(logPrefix + "Calling API URL: " + apiUrl);

    var res = httpc.getS(new URL(apiUrl), null);

    $ivr.getLogger().info(logPrefix + "HTTP Status: " + res.responseCode);
    $ivr.getLogger().info(logPrefix + "Response Body: " + res.body);

    if (res.responseCode !== 200) {
        $ivr.getLogger().warn(logPrefix + "API returned non-200 status: " + res.responseCode);
        return { apiUrl: apiUrl, responseCode: res.responseCode, katakanaName: "", rawBody: res.body };
    }

    var katakanaName = parseKatakanaNameFromBody(res.body);
    return { apiUrl: apiUrl, responseCode: res.responseCode, katakanaName: katakanaName, rawBody: res.body };
}

