// 2) Function trả về luôn data (hỗ trợ mock)
//    - Nếu mockData được truyền vào, trả về ngay mockData (không gọi API)
//    - Nếu không, gọi API và trả về đầy đủ dữ liệu
function getPhoneToNameData(opts) {
    // opts: { host, tenantId, officeId, deployTo, logPrefix, mockData }
    if (opts && opts.mockData) {
        return {
            apiUrl: "(mock)",
            responseCode: 200,
            katakanaName: String(opts.mockData.katakanaName || ""),
            rawBody: String(opts.mockData.rawBody || "{}"),
            isMock: true
        };
    }
	
	// fetch data from cache
	var cachedData = $ivr.getObject("phoneToNameResult");
	if (cachedData != undefined && cachedData.katakanaName != undefined && cachedData.katakanaName.length > 0) {
		$ivr.getLogger().warn(logPrefix + "get phone to name from cache " + JSON.stringify(cachedData));
	    return cachedData;
	}
	
	// fetch data via api
    return fetchKatakanaNameByPhone(opts.host, opts.tenantId, opts.officeId, opts.deployTo, opts.logPrefix, opts.phoneNumber);
}

