  var seqNumber = $runner.get("seq") ? $runner.get("seq") : 1;
  var utterance = {
      seq:seqNumber,
      messageType:0,
      text:text,
      utteranceType:"MESSAGE",
      startMsec:$ivr.exec("save2db", "parseTimestamp", startTime.toISOString()),
      endMsec:$ivr.exec("save2db", "parseTimestamp", endTime.toISOString())
  };
  var operationSuccess = $ivr.exec("save2db", "save", JSON.stringify({utterance:utterance}));
  if (!operationSuccess) {
      $runner.getLogger().error("[Phone 2 name node data] Failed to save utterance.");
  } else {
    $runner.set("seq", (seqNumber + 1));
    $runner.getLogger().info("[Phone 2 nam node data] Successfully saved utterance and updated seq number to " + (seqNumber + 1));
  }
} catch (error) {
  $runner.getLogger().error("[Phone 2 name node data] Failed to save utterance: " + error);
}
}

