/**
 * Formats a date string to 'yyyy-MM-dd HH:mm' format.
 * If the input is not a valid date or is in the wrong format, it returns an empty string.
 * @param {string} dateStr - The input date string.
 * @returns {string} The formatted date string or an empty string.
 */
var formatTargetDate = function(dateStr) {
    // Return empty string if input is null, undefined, or not a string
    if (!dateStr || typeof dateStr !== 'string' || dateStr.trim() === '') {
        return "";
    }

    // Attempt to create a Date object from the input string
    var date = new Date(dateStr);

    // Check if the created date is valid
    if (isNaN(date.getTime())) {
        $runner.getLogger().warn(logPrefix + "Invalid date string provided: " + dateStr);
        return "";
    }

    // Format the date into yyyy-MM-dd HH:mm
    var year = date.getFullYear();
    var month = ('0' + (date.getMonth() + 1)).slice(-2); // Months are 0-based
    var day = ('0' + date.getDate()).slice(-2);
    var hours = ('0' + date.getHours()).slice(-2);
    var minutes = ('0' + date.getMinutes()).slice(-2);

    return year + '-' + month + '-' + day + ' ' + hours + ':' + minutes;
};

/**
 * Get department name from runner object or return default
 * @returns {string} department name
 */
var getDepartmentName = function() {
    var departmentName = $runner.getObject("department-name");
    return departmentName ? departmentName : "登録なし";
}

/** 
 * Map error codes to module result strings
 * @param {jsonData} resBody 
 * @returns {string} module result
 */
var getModuleResult = function(resBody) {
    var errorCode = resBody.errorCode;
    if (errorCode === "" && resBody.hasAvailableSlots) return "空きがある";
    if (errorCode === "" && !resBody.hasAvailableSlots) return "空きがない";

    switch (String(errorCode)) {
        case "ERROR_CODE_ACCEPTABLE_PERIOD_CHANGED":
        case "ERROR_CODE_CALENDAR_CHANGED":
            return "受付不可期間";
        case "OUT_OF_CAPACITY":
            return "空きがない";
        default:
            return "その他: 見つからない、非公開など";
    }
}

/** 
 * Make HTTP POST request
 * @param {object} jsonData
 * @returns {object} HTTP response
 */
var makeHttpPostRequest = function(requestPayload) {
    if (!url || !requestPayload) {
        $runner.getLogger().error("Invalid data for HTTP request");
        return null;
    }
    var client = HttpClient.newBuilder()
        .connectTimeout(Duration.ofSeconds(connectTimeout))
        .build();

    var req = HttpRequest.newBuilder()
        .uri(URI.create(url))
        .header("Content-Type", "application/json")
        .timeout(Duration.ofSeconds(requestTimeout))
        .POST(HttpRequest.BodyPublishers.ofString(requestPayload))
        .build();

    return client.send(req, HttpResponse.BodyHandlers.ofString());
};

