//======================================================
/**
 * Extracts the content from a Google TTS tag {tts_g:...} within a prompt string.
 * @param {string} prompt The full prompt string containing the TTS tag.
 * @returns {string} The content inside the TTS tag, or an empty string if not found.
 */
function getTranscribe(prompt) {
  if (!prompt) {
    return "";
  }
  
  var match = prompt.match(/\{tts_g:([^}]*)\}/);
  if (!match) {
    return "";
  }
  var content = match[1];
  return content.replace(/<[^>]+>/g, "");
}

function parseTimestampToMillis(dateTime) {
  var millisecond = $ivr.exec("save2db", "parseTimestamp", dateTime);
  var callTransferTimeKey = "transfer_time_" + $ivr.getRID();
  var transferTime = $runner.getObject(callTransferTimeKey);

  // Subtract the transfer time from the total time in milliseconds, because sound contains no transfer.
  if (transferTime) {
    millisecond = millisecond - transferTime;
  }
  return millisecond;
}

function savePrompt(prompt, startTime, endTime) {
  // --- Save Interaction to Database ---
  try {
    var seqNumber = $runner.get("seq") ? $runner.get("seq") : 1;
    var utterance = {
        seq:seqNumber,
        messageType:0,
        text:getTranscribe(prompt),
        utteranceType:"MESSAGE",
        startMsec:parseTimestampToMillis(startTime.toISOString()),
        endMsec:parseTimestampToMillis(endTime.toISOString())
    };
    var operationSuccess = $ivr.exec("save2db", "save", JSON.stringify({utterance:utterance}));
    if (!operationSuccess) {
        $runner.getLogger().error("[Call-transfer node data] Failed to save utterance.");
    } else {
      $runner.set("seq", (seqNumber + 1));
      $runner.getLogger().info("[Call-transfer node data] Successfully saved utterance and updated seq number to " + (seqNumber + 1));
    }
  } catch (error) {
    $runner.getLogger().error("[Call-transfer node data] Failed to save utterance: " + error);
  }
}

function speakResult(promptName) {
  var prompt = $runner.getProperty(promptName);
  if( ( typeof $ivr ) == 'object' && prompt.length() > 0 ){
    var startTime = new Date();
    $ivr.play( prompt, false );
    var endTime = new Date();
    savePrompt(prompt, startTime, endTime);
  }
}

function transferSuccess(ntype) {
  if( ntype == 1 || ntype == 2 ) {
    $ivr.dropcall();
  } else {
