  }
}

function saveTransferTimeToSession(startTime, endTime) {
  var startTimeMillis = $ivr.exec("save2db", "parseTimestamp", startTime.toISOString());
  var endTimeMillis = $ivr.exec("save2db", "parseTimestamp", endTime.toISOString());
  var key = "transfer_time_" + $ivr.getRID();
  var value = endTimeMillis - startTimeMillis;
  $runner.setObject(key, value);
  return value;
}

