/**
 * Module: Check Frame Availability (枠空き確認)
 * Objective: Check if a department frame exists and has available booking capacity
 * 
 * API validates:
 * - Frame exists in system
 * - Frame is valid (not expired/deleted/draft)
 * - Frame has sufficient capacity
 * 
 * Request: POST { officeId, frameTitle }
 * Response: 
 * - If frame exists: { frameId, frameTitle, canBook: true/false }
 * - If frame not found: {} (empty response)
 * 
 * canBook = false when:
 * - Frame expired
 * - Frame deleted
 * - Frame is draft
 * - No capacity available
 * 
 * Result:
 * - CAN_BOOK: Frame is available for booking
 * - CANNOT_BOOK: Frame not available or not found
 */

// ==================================================================
// Java classes
var URI = Java.type("java.net.URI");
var HttpClient = Java.type("java.net.http.HttpClient");
var HttpRequest = Java.type("java.net.http.HttpRequest");
var HttpResponse = Java.type("java.net.http.HttpResponse");
var Duration = Java.type("java.time.Duration");

// ==================================================================
// Constants
var RESULT_CAN_BOOK = "CAN_BOOK";
var RESULT_CANNOT_BOOK = "CANNOT_BOOK";

// ==================================================================
// Utilities
var getProperty = function (key, defVal) {
    var value = $runner.getProperty(key);
    if (!value) {
        value = $runner.getProperty(".smart-menkai.check-frame-availability." + key);
        if (!value) {
            $runner.getLogger().warn("Property '" + key + "' is not set. Using default value: " + defVal);
        }
    }
    return value ? value : defVal;
};

/**
 * Build request body for frame availability check
 * @param {string} officeId - Office ID
 * @param {string} frameTitle - Frame title (department name)
 * @returns {string} JSON string
 */
function buildRequestBody(officeId, frameTitle) {
    var body = {
        officeId: officeId,
        frameTitle: frameTitle
    };
    return JSON.stringify(body);
}

/**
 * Parse response body to extract frame info
 * @param {string} body - Response body
 * @param {string} logPrefix - Log prefix for context
 * @param {object} logger - Logger instance
 * @returns {object} Parsed response with frameId, frameTitle, canBook, frameNotFound
 */
function parseResponse(body, logPrefix, logger) {
    try {       
        var json = JSON.parse(body);
        if (json.frameId == null) {
            logger.warn(logPrefix + "Response contains null frameId - frame not found in system");
            return {
                frameId: "",
                frameTitle: "",
                canBook: false,
                frameNotFound: true
            };
        }
        
        var frameId = String(json.frameId || "");
        var frameTitle = String(json.frameTitle || "");
        var canBook = !!json.canBook;
        var contactRequired = !!json.contactRequired;
        var visitorCountOptions = Array.isArray(json.visitorCountOptions) ? json.visitorCountOptions : [];
        
        logger.info(logPrefix + "Parsed Response - frameId: " + frameId + ", frameTitle: " + frameTitle + ", canBook: " + canBook + ", contactRequired: " + contactRequired + ", visitorCountOptions: " + JSON.stringify(visitorCountOptions));
        
        return {
            frameId: frameId,
            frameTitle: frameTitle,
            canBook: canBook,
            frameNotFound: false,
            contactRequired: contactRequired,
            visitorCountOptions: visitorCountOptions
        };
    } catch (e) {
        logger.error(logPrefix + "Failed to parse response: " + e.message);
        return {
            frameId: "",
            frameTitle: "",
            canBook: false,
            frameNotFound: false
        };
    }
}

/**
 * Call API to check frame availability
 * @param {string} apiUrl - API endpoint URL
 * @param {string} requestBody - JSON request body
 * @param {string} logPrefix - Log prefix for context
 * @param {object} logger - Logger instance
 * @returns {object} Response with statusCode, parsed data, and frameNotFound flag
 */
function checkFrameAvailability(apiUrl, requestBody, logPrefix, logger) {
    logger.info(logPrefix + "Calling API URL: " + apiUrl);
    logger.info(logPrefix + "Request Body: " + requestBody);
    
    var connectTimeout = parseInt(getProperty("connect_timeout", 10), 10);
    var requestTimeout = parseInt(getProperty("request_timeout", 10), 10);

    var client = HttpClient.newBuilder()
        .connectTimeout(Duration.ofSeconds(connectTimeout))
        .build();

    var req = HttpRequest.newBuilder()
        .uri(URI.create(apiUrl))
        .header("Content-Type", "application/json")
        .timeout(Duration.ofSeconds(requestTimeout))
        .POST(HttpRequest.BodyPublishers.ofString(requestBody))
        .build();

    var res = client.send(req, HttpResponse.BodyHandlers.ofString());
    
    logger.info(logPrefix + "HTTP Status: " + res.statusCode());
    logger.info(logPrefix + "Response Body: " + res.body());
    
    if (res.statusCode() !== 200) {
        logger.warn(logPrefix + "API returned non-200 status: " + res.statusCode());
        return {
            statusCode: res.statusCode(),
            frameId: "",
            frameTitle: "",
            canBook: false,
            frameNotFound: false
        };
    }
    
    var parsed = parseResponse(res.body(), logPrefix, logger);
    $runner.setObject("visitor-count-options", parsed.visitorCountOptions);
    $runner.setObject("contact-required", parsed.contactRequired);
    
    return {
        statusCode: res.statusCode(),
        frameId: parsed.frameId,
        frameTitle: parsed.frameTitle,
        canBook: parsed.canBook,
        frameNotFound: parsed.frameNotFound
    };
}

/**
 * Get frame title from runner object
 * @param {string} logPrefix - Log prefix for context
 * @param {object} logger - Logger instance
 * @returns {string} Frame title or empty string
 */
function getFrameTitle(logPrefix, logger) {
    var frameTitle = $runner.getObject("frame-title");
    
    if (!frameTitle || String(frameTitle) === "") {
        logger.warn(logPrefix + "frame-title object is not set or empty");
        return "";
    }
    
    logger.info(logPrefix + "Retrieved frame-title: " + frameTitle);
    return String(frameTitle);
}

