// Main

// Input
var apiUrl = getProperty("url", "");
var officeId = getProperty(".office_id", "");
var tenantId = $ivr.getTenant();
var deployTo = $ivr.getMyNumber();
var callId = $ivr.getRID();

// Log prefix
var logPrefix = "[" + tenantId + "][" + officeId + "][" + deployTo + "][" + callId + "] ";

try {
    // Validate required configs
    if (!apiUrl || String(apiUrl).trim() === "") {
        $runner.getLogger().error(logPrefix + "Cannot proceed: API url is empty (.smart-menkai.check-frame-availability.url)");
        $runner.setResult(RESULT_CANNOT_BOOK);
        return;
    }
    if (!officeId || String(officeId).trim() === "") {
        $runner.getLogger().error(logPrefix + "Cannot proceed: officeId is empty (.office_id)");
        $runner.setResult(RESULT_CANNOT_BOOK);
        return;
    }
    // Get frame title from runner object
    var frameTitle = getFrameTitle(logPrefix, $runner.getLogger());
    
    // Validate frame title - early return on error
    if (!frameTitle || frameTitle === "") {
        $runner.getLogger().error(logPrefix + "Cannot proceed: frame-title is empty");
        $runner.setResult(RESULT_CANNOT_BOOK);
        return;
    }
    
    // Build request body
    var requestBody = buildRequestBody(officeId, String(frameTitle).trim());
    
    // Call API to check frame availability
    var result = checkFrameAvailability(apiUrl, requestBody, logPrefix, $runner.getLogger());
    
    // Check if frame not found (response empty object) - early return
    if (result.frameNotFound) {
        $runner.getLogger().warn(logPrefix + "Frame not found in system - cannot book");
        $runner.setResult(RESULT_CANNOT_BOOK);
        return;
    }
    
    // Check if frame cannot be booked - early return
    if (!result.canBook) {
        $runner.getLogger().info(logPrefix + "Frame not available - may be expired/deleted/draft or no capacity");
        $runner.setResult(RESULT_CANNOT_BOOK);
        return;
    }
    
    // Success case - frame can be booked
    $runner.getLogger().info(logPrefix + "Frame is available for booking");
    
    // Set frame-id object for later use
    if (result.frameId && String(result.frameId) !== "") {
        $runner.setObject("frame-id", result.frameId);
        $runner.getLogger().info(logPrefix + "Set frame-id object: " + result.frameId);
    }
    
    $runner.setResult(RESULT_CAN_BOOK);

} catch (e) {
    $runner.getLogger().error(logPrefix + "Error during frame availability check: " + e.message);
    $runner.setResult(RESULT_CANNOT_BOOK);
}

