/**
 * Format datetime string from yyyy-mm-dd hh:mm to yyyy-mm-ddThh:mm
 * @param {string} dateTimeStr - The datetime string in format yyyy-mm-dd hh:mm
 * @returns {string} Formatted datetime string in format yyyy-mm-ddThh:mm, or original string if invalid
 */
var formatDateTime = function(dateTimeStr) {
    // Handle null, undefined, or non-string values
    if (!dateTimeStr || typeof dateTimeStr !== 'string') {
        return dateTimeStr || "";
    }
    
    // Handle empty string
    if (dateTimeStr.trim() === '') {
        return "";
    }
    
    // Check if the format matches yyyy-mm-dd hh:mm
    var dateTimePattern = /^(\d{4})-(\d{2})-(\d{2}) (\d{2}):(\d{2})$/;
    var match = dateTimePattern.exec(dateTimeStr);
    if (!match) {
        // If format is incorrect, return original string
        return dateTimeStr;
    }
    
    // Validate date and time values
    var year = parseInt(match[1], 10);
    var month = parseInt(match[2], 10);
    var day = parseInt(match[3], 10);
    var hour = parseInt(match[4], 10);
    var minute = parseInt(match[5], 10);
    
    // Basic validation: month (1-12), day (1-31), hour (0-23), minute (0-59)
    if (month < 1 || month > 12 || day < 1 || day > 31 || hour > 23 || minute > 59) {
        // If values are invalid, return original string
        return dateTimeStr;
    }
    
    // Replace space between date and time with 'T'
    return dateTimeStr.replace(' ', 'T');
}

