 * Example valid: 2025-08-25 15:00
 * - Checks regex pattern
 * - Checks hour/minute ranges
 * - Checks resulting Date is valid
 * @param {string} value
 * @returns {boolean}
 */
function isValidDesiredTime(value) {
    if (!value || typeof value !== "string") {
        return false;
    }
    var pattern = /^\d{4}-\d{2}-\d{2} \d{2}:\d{2}$/;
    if (!pattern.test(value)) {
        return false;
    }
    // Range checks
    var dateAndTime = value.split(" ");
    var ymd = dateAndTime[0].split("-");
    var hm = dateAndTime[1].split(":");
    var hh = parseInt(hm[0], 10);
    var mm = parseInt(hm[1], 10);
    if (isNaN(hh) || isNaN(mm) || hh < 0 || hh > 23 || mm < 0 || mm > 59) {
        return false;
    }
    // Date validity
    var d = new Date((ymd[0] + "-" + ymd[1] + "-" + ymd[2]) + "T" + hm[0] + ":" + hm[1] + ":00");
    return !isNaN(d.getTime());
}

