// Get booking parameters (direct getters)
var phoneNumber = String($ivr.getOtherNumber() || "");
var hasMasterData = String($runner.getObject("has-master-data") || "false") === "true";

try {
    // Validate API configuration
    if (!apiUrl || String(apiUrl).trim() === "") {
        $runner.getLogger().error(logPrefix + "Cannot proceed: API URL is empty (.smart-menkai.booking_pre_check.url)");
        $runner.setResult(RESULT_ERROR);
        return;
    }
    
    if (!officeId || String(officeId).trim() === "") {
        $runner.getLogger().error(logPrefix + "Cannot proceed: officeId is empty (.office_id)");
