        return;
    }
    
    // Validate required parameters - early return on error
    var frameSettingId = String($runner.getObject("frame-id") || "");
    if (!frameSettingId) {
        $runner.getLogger().error(logPrefix + "Cannot proceed: frame-id is empty - " + getErrorMessage("FRAME_SETTING_NOT_FOUND"));
        $runner.setResult(RESULT_ERROR);
        return;
    }

    // Get visitorId (optional) and desiredBookingStartTime (required)
    var visitorId = String($runner.getObject("visitor-id") || "");
    if (!visitorId && hasMasterData) {
        $runner.getLogger().error(logPrefix + "Cannot proceed: visitor-id is empty - " + getErrorMessage("VISITOR_INFO_MISSING"));
        $runner.setResult(RESULT_ERROR);
        return;
    }

    var desiredBookingStartTime = String($runner.getObject("booking-start-time") || "");
    $runner.getLogger().info(logPrefix + "Input booking-start-time: " + desiredBookingStartTime);
    
    if (!desiredBookingStartTime || !isValidDesiredTime(desiredBookingStartTime)) {
        $runner.getLogger().error(logPrefix + "Cannot proceed: booking-start-time invalid - " + getErrorMessage("INVALID_ARGUMENT") + " | Input value: '" + desiredBookingStartTime + "'");
        $runner.setResult(RESULT_ERROR);
        return;
    }

    // Build request body (format desired time to ISO minute)
    var desiredStartIso = toIsoMinute(desiredBookingStartTime);
    var requestBody = buildRequestBody(officeId, frameSettingId, phoneNumber, visitorId, desiredStartIso, false, hasMasterData);
    
    // Call API to pre-check booking
    var result = bookingPreCheck(apiUrl, requestBody, logPrefix, $runner.getLogger());
    
    // Case 1: canBook = true - Set booking-end-time and return CAN_BOOK
    if (result.canBook) {
        $runner.getLogger().info(logPrefix + "Booking pre-check passed: CAN_BOOK");
        
        if (result.bookingEndTime) {
            var bookingEndTimeFormatted = fromIsoMinute(result.bookingEndTime);
            $runner.setObject("booking-end-time", bookingEndTimeFormatted);
            $runner.getLogger().info(logPrefix + "Set booking-end-time: " + bookingEndTimeFormatted);
        }
        
        $runner.setResult(RESULT_CAN_BOOK);
        return;
    }
    
    // Case 2: canBook = false - Return CANNOT_BOOK
    // Note: Next available time slot should be handled by booking-suggest-time module
    $runner.getLogger().warn(logPrefix + "Booking pre-check failed - " + getErrorMessage(result.errorCode) + " (code=" + result.errorCode + ")");
    if (result.errorCode === "SM_E0021_BOOKING_DETAIL_EXISTS_IN_DAY" || result.errorCode === "SM_E00013_EXISTED_BOOKING_IN_THIS_DAY") {
        $runner.setResult(EXISTED_BOOKING_IN_THIS_DAY);
        return;
    } else if(result.errorCode === "PATIENT.PATIENT_DISCHARGED") {
        $runner.setResult(RESULT_PATIENT_DISCHARGED);
        return;
    }

    $runner.setResult(RESULT_CANNOT_BOOK);
} catch (e) {
    $runner.getLogger().error(logPrefix + "Error during booking pre-check: " + e.message);
    $runner.setResult(RESULT_ERROR);
}

