/**
 * Module: Incoming Phone Number Judgment (着信電話番号判定)
 * Objective: Classify the incoming phone number into:
 * - 非通知 (Anonymous): null or "anonymous"
 * - 携帯 (Mobile JP): 070/080/090 + 8 digits (11 digits total)
 * - 固定 (Fixed JP): 050 + 8 digits (11 digits) OR 0X + 8 digits (10 digits)
 * - 海外 (International): Starts with '+' but NOT '+81'
 * - その他 (Unknown): All other cases
 */

// ==================================================================
// Constants
var CLASSIFICATION_ANONYMOUS = "非通知";
var CLASSIFICATION_MOBILE = "携帯";
var CLASSIFICATION_FIXED = "固定";
var CLASSIFICATION_INTERNATIONAL = "海外";
var CLASSIFICATION_UNKNOWN = "その他";

// ==================================================================
// Utilities
var getProperty = function (key, defVal) {
    var value = $runner.getProperty(key);
    if (!value) {
        $runner.getLogger().warn("Property '" + key + "' is not set. Using default value: " + defVal);
    }
    return value ? value : defVal;
};

/**
 * Check if phone number is empty or anonymous
 * @param {string} phoneRaw - Raw phone number input
 * @returns {boolean}
 */
function isAnonymousPhone(phoneRaw) {
    if (!phoneRaw || String(phoneRaw) === "") {
        return true;
    }
    return /^(anonymous|null)$/i.test(String(phoneRaw).trim());
}

/**
 * Check if phone number is international (not Japan)
 * @param {string} phone - Trimmed phone number
 * @returns {boolean}
 */
function isInternationalPhone(phone) {
    return phone.startsWith("+") && !phone.startsWith("+81");
}

/**
 * Normalize phone number: Remove +81 prefix and keep only digits
 * @param {string} phone - Trimmed phone number
 * @returns {string}
 */
function normalizePhoneNumber(phone) {
    return phone.replace(/^\+81/, "0").replace(/[^\d]/g, "");
}

/**
 * Check if digits match mobile pattern
 * 11 digits starting with 070, 080, or 090
 * @param {string} digits - Normalized digits
 * @returns {boolean}
 */
function isMobilePhone(digits) {
    return /^(070|080|090)\d{8}$/.test(digits);
}

/**
 * Check if digits match fixed line pattern
 * 11 digits starting with 050 (IP Phone) OR 10 digits starting with 0 (Landline)
 * @param {string} digits - Normalized digits
 * @returns {boolean}
 */
function isFixedPhone(digits) {
    return /^050\d{8}$/.test(digits) || /^0\d{9}$/.test(digits);
}

/**
 * Get incoming phone number
 * Priority: Property .incomingPhone (for testing) > getOtherNumber() (actual call)
 * @param {string} logPrefix - Logging prefix for context
 * @param {object} logger - Logger instance
 * @returns {string} Raw phone number
 */
function getIncomingPhoneNumber(logPrefix, logger) {
    // Try to get from property first (test value from Flow Designer)
    var phoneRaw = getProperty(".incomingPhone", "");
    
    if (!phoneRaw || String(phoneRaw) === "") {
        // Get actual incoming number
        phoneRaw = $ivr.getOtherNumber();
        logger.info(logPrefix + "Incoming Source: getOtherNumber | Value: " + phoneRaw);
    } else {
        logger.info(logPrefix + "Incoming Source: Property .incomingPhone | Value: " + phoneRaw);
    }
    
    return phoneRaw;
}

/**
 * Classify phone number based on Japanese telecom rules
 * @param {string} phoneRaw - Raw phone number input
 * @param {string} logPrefix - Logging prefix for context
 * @param {object} logger - Logger instance
 * @returns {string} Classification result
 */
function classifyPhoneNumber(phoneRaw, logPrefix, logger) {
    // Case 1: Anonymous (非通知)
    if (isAnonymousPhone(phoneRaw)) {
        logger.info(logPrefix + "Classification: " + CLASSIFICATION_ANONYMOUS + " (Anonymous/Null)");
        return CLASSIFICATION_ANONYMOUS;
    }

    var phone = String(phoneRaw).trim();

    // Case 2: International (海外)
    // Starts with '+' but NOT '+81'
    if (isInternationalPhone(phone)) {
        logger.info(logPrefix + "Classification: " + CLASSIFICATION_INTERNATIONAL + " (International) | Raw: " + phone);
        return CLASSIFICATION_INTERNATIONAL;
    }

    // Normalize: Remove +81 prefix if exists, keep only digits
    var digits = normalizePhoneNumber(phone);
    logger.info(logPrefix + "Normalized Digits: " + digits + " | Length: " + digits.length);

    // Case 3a: Mobile (携帯)
    if (isMobilePhone(digits)) {
        logger.info(logPrefix + "Classification: " + CLASSIFICATION_MOBILE + " (Mobile) | Pattern: 070/080/090");
        return CLASSIFICATION_MOBILE;
    }

    // Case 3b: Fixed (固定)
    if (isFixedPhone(digits)) {
        logger.info(logPrefix + "Classification: " + CLASSIFICATION_FIXED + " (Fixed) | Digits: " + digits);
        return CLASSIFICATION_FIXED;
    }

    // Case 4: Unknown (その他)
    logger.info(logPrefix + "Classification: " + CLASSIFICATION_UNKNOWN + " (Unknown) | Digits: " + digits);
    return CLASSIFICATION_UNKNOWN;
}

