/**
 * Module: Incoming Phone Number Category Classifier (着信電話番号カテゴリ分類)
 * Objective: Classify the incoming phone number into 8 categories based on HA0027 settings:
 * - ブラックリスト (Black list): Phone is registered as blacklist in HA0027 (enable phone icon)
 * - リスト1 (List1): Phone is registered with list1 checked ON
 * - リスト2 (List2): Phone is registered with list2 checked ON
 * - リスト3 (List3): Phone is registered with list3 checked ON
 * - リスト4 (List4): Phone is registered with list4 checked ON
 * - リスト5 (List5): Phone is registered with list5 checked ON
 * - その他 (Other): Phone is not in any of the above lists
 * - ERROR: API call failed, parsing error, or exception occurred
 * 
 * Priority: If multiple items are checked (e.g., blacklist + list5), 
 * prioritize in order from top to bottom (blacklist first).
 */

// ==================================================================
// Constants
var CLASSIFICATION_BLACK_LIST = "ブラックリスト";
var CLASSIFICATION_LIST1 = "リスト1";
var CLASSIFICATION_LIST2 = "リスト2";
var CLASSIFICATION_LIST3 = "リスト3";
var CLASSIFICATION_LIST4 = "リスト4";
var CLASSIFICATION_LIST5 = "リスト5";
var CLASSIFICATION_OTHER = "その他";
var CLASSIFICATION_ERROR = "ERROR";

// Category keys in priority order
var CATEGORY_KEYS = ["list1", "list2", "list3", "list4", "list5"];

// ==================================================================
// Java classes
var URI = Java.type("java.net.URI");
var HttpClient = Java.type("java.net.http.HttpClient");
var HttpRequest = Java.type("java.net.http.HttpRequest");
