 * @param {string} host - API host URL
 * @param {string} tenantId - Tenant ID
 * @param {string} officeId - Office ID
 * @param {string} deployTo - Deploy to (phone number)
 * @param {string} phoneNumber - Incoming phone number
 * @returns {string} Complete API URL
 */
function buildApiUrl(host, tenantId, officeId, deployTo, phoneNumber) {
    return host + "?tenantId=" + tenantId + "&officeId=" + officeId + "&deployTo=" + deployTo + "&phoneNumber=" + phoneNumber;
