/**
 * Parse category assignments from API response body
 * @param {string} body - JSON response body
 * @param {string} logPrefix - Log prefix for context
 * @param {object} logger - Logger instance
 * @returns {object} Parsed data with blackList, categoryAssignments, and error flag
 */
function parseResponse(body, logPrefix, logger) {
    try {
        var json = JSON.parse(body);
        var blackList = !!json.blackList;
        
        var categoryAssignments = [];
        if (json.categoryAssignments && Array.isArray(json.categoryAssignments)) {
            for (var i = 0; i < json.categoryAssignments.length; i++) {
                var item = json.categoryAssignments[i];
                categoryAssignments.push({
                    key: String(item.key || ""),
                    enabled: !!item.enabled
                });
            }
        }
        
        logger.info(logPrefix + "Parsed Response - blackList: " + blackList + ", categoryAssignments count: " + categoryAssignments.length);
        
        return {
            blackList: blackList,
            categoryAssignments: categoryAssignments,
            hasError: false
        };
    } catch (e) {
        logger.error(logPrefix + "Failed to parse response: " + e.message);
        return {
            blackList: false,
            categoryAssignments: [],
            hasError: true,
            errorMessage: "Parse error: " + e.message
        };
    }
}

/**
 * Fetch category assignments from API
 * @param {string} apiUrl - API endpoint URL
 * @param {string} logPrefix - Log prefix for context
 * @param {object} logger - Logger instance
 * @returns {object} API response with statusCode, parsed data, and error flag
 */
function fetchCategoryAssignments(apiUrl, logPrefix, logger) {
    try {
        logger.info(logPrefix + "Calling API URL: " + apiUrl);

        var connectTimeout = parseInt(getProperty("connect_timeout", 10), 10);
        var requestTimeout = parseInt(getProperty("request_timeout", 10), 10);

        var client = HttpClient.newBuilder()
            .connectTimeout(Duration.ofSeconds(connectTimeout))
            .build();

        var req = HttpRequest.newBuilder()
            .uri(URI.create(apiUrl))
            .timeout(Duration.ofSeconds(requestTimeout))
            .GET()
            .build();

        var res = client.send(req, HttpResponse.BodyHandlers.ofString());

        logger.info(logPrefix + "HTTP Status: " + res.statusCode());
        logger.info(logPrefix + "Response Body: " + res.body());

        if (res.statusCode() !== 200) {
            logger.error(logPrefix + "API returned non-200 status: " + res.statusCode());
            return {
                statusCode: res.statusCode(),
                blackList: false,
                categoryAssignments: [],
                hasError: true,
                errorMessage: "HTTP error: " + res.statusCode()
            };
        }

        var parsed = parseResponse(res.body(), logPrefix, logger);

        return {
            statusCode: res.statusCode(),
            blackList: parsed.blackList,
            categoryAssignments: parsed.categoryAssignments,
            hasError: parsed.hasError,
            errorMessage: parsed.errorMessage
        };
    } catch (e) {
        logger.error(logPrefix + "Exception during API call: " + e.message);
        return {
            statusCode: 0,
            blackList: false,
            categoryAssignments: [],
            hasError: true,
            errorMessage: "Exception: " + e.message
        };
    }
}

