/**
 * Classify phone number based on HA0027 category assignments
 * Priority order: Black list > List1 > List2 > List3 > List4 > List5 > Other
 * @param {boolean} blackList - Whether phone is in black list
 * @param {Array} categoryAssignments - Array of category assignments with key and enabled
 * @param {string} logPrefix - Logging prefix for context
 * @param {object} logger - Logger instance
 * @returns {string} Classification result
 */
function classifyPhoneNumber(blackList, categoryAssignments, logPrefix, logger) {
    // Priority 1: Black list (ブラックリスト)
    if (blackList) {
        logger.info(logPrefix + "Classification: " + CLASSIFICATION_BLACK_LIST + " (Black list)");
        return CLASSIFICATION_BLACK_LIST;
    }

    // Priority 2-6: Check List1 to List5 in order
    // Build a map for quick lookup
    var enabledCategories = {};
    if (categoryAssignments && categoryAssignments.length > 0) {
        for (var i = 0; i < categoryAssignments.length; i++) {
            var assignment = categoryAssignments[i];
            if (assignment.enabled && assignment.key) {
                enabledCategories[assignment.key] = true;
            }
        }
    }

    // Check in priority order: list1, list2, list3, list4, list5
    for (var j = 0; j < CATEGORY_KEYS.length; j++) {
        var key = CATEGORY_KEYS[j];
        if (enabledCategories[key]) {
            var classification = "リスト" + (j + 1);
            logger.info(logPrefix + "Classification: " + classification + " (List" + (j + 1) + ")");
            return classification;
        }
    }

    // Priority 7: Other (その他)
    logger.info(logPrefix + "Classification: " + CLASSIFICATION_OTHER + " (Other - not in any list)");
    return CLASSIFICATION_OTHER;
}

