}

/**
 * Normalize giá trị để so sánh (chuyển string "true"/"false" thành boolean, string số thành number)
 * @param {*} value - Giá trị cần normalize
 * @returns {*} Giá trị đã được normalize
 */
function normalizeValue(value) {
    if (value === null || value === undefined) {
        return value;
    }
    
    // Nếu là string, thử chuyển về boolean hoặc number
    if (typeof value === "string") {
        var lowerStr = value.toLowerCase().trim();
        if (lowerStr === "true") return true;
        if (lowerStr === "false") return false;
        
        // Nếu là số, chuyển về number
        if (!isNaN(value) && value.trim() !== "") {
            var numValue = Number(value);
            if (!isNaN(numValue)) {
                return numValue;
            }
        }
    }
    
    return value;
}

/**
 * So sánh bằng (EQUAL)
 * @param {*} actualValue - Giá trị thực tế từ session
 * @param {*} expectValue - Giá trị mong đợi
 * @returns {boolean} true nếu bằng nhau
 */
function compareEqual(actualValue, expectValue) {
    // Normalize cả hai giá trị trước khi so sánh
    var normalizedActual = normalizeValue(actualValue);
    var normalizedExpected = normalizeValue(expectValue);
    
    // So sánh boolean
    if (typeof normalizedActual === "boolean" || typeof normalizedExpected === "boolean") {
        return normalizedActual === normalizedExpected;
    }
    
    // So sánh number
    if (typeof normalizedActual === "number" || typeof normalizedExpected === "number") {
        return Number(normalizedActual) === Number(normalizedExpected);
    }
    
    // So sánh string
    return String(normalizedActual) === String(normalizedExpected);
}

/**
 * So sánh chứa (CONTAINS)
 * @param {*} actualValue - Giá trị thực tế từ session
 * @param {*} expectValue - Giá trị mong đợi
 * @returns {boolean} true nếu chứa
 */
function compareContains(actualValue, expectValue) {
    // Nếu actualValue là mảng
    if (Array.isArray(actualValue)) {
        var expectedStr = String(expectValue);
        for (var i = 0; i < actualValue.length; i++) {
            if (String(actualValue[i]) === expectedStr) {
                return true;
            }
        }
        return false;
    }
    
    // Nếu actualValue là string
    if (typeof actualValue === "string") {
        return actualValue.indexOf(String(expectValue)) !== -1;
    }
    
    // Fallback: so sánh bằng
    return String(actualValue) === String(expectValue);
}

/**
 * Thực hiện so sánh dựa trên comparisonType
 * @param {*} actualValue - Giá trị thực tế từ session
 * @param {*} expectValue - Giá trị mong đợi
 * @param {string} comparisonType - Kiểu so sánh (EQUAL hoặc CONTAINS)
 * @returns {boolean} kết quả so sánh
 */
function performComparison(actualValue, expectValue, comparisonType) {
    var type = String(comparisonType).toUpperCase();
    
    if (type === "EQUAL") {
        return compareEqual(actualValue, expectValue);
    }
    
    if (type === "CONTAINS") {
        return compareContains(actualValue, expectValue);
    }
    
    // Kiểu so sánh không hợp lệ
    $runner.getLogger().error("[" + $ivr.getRID() + "] [conditional-comparison] Invalid comparisonType: " + comparisonType + ". Must be EQUAL or CONTAINS");
    return false;
}

function resolveInputValue(input) {
  // If it is just a single variable (e.g. "<% varName %>")
  var onlyVarMatch = input.match(/^<%\s*([\w\-]+)\s*%>$/);
  if (onlyVarMatch) {
    var varName = onlyVarMatch[1];
    return $ivr.exec("system-variable", "getSystemVariableValue", varName); // return variable value
  }

  // Otherwise, replace template variables in the
  return $ivr.exec("system-variable", "replaceTemplateVariables", input);
}

// =================================================================
// Main execution
// =================================================================

// Lấy các input từ module properties
var key = $runner.getProperty("key");
var expectValue = $runner.getProperty("expectValue");
var comparisonType = $runner.getProperty("comparisonType");

// Log thông tin input
$runner.getLogger().info("[" + $ivr.getRID() + "] [conditional-comparison] key=" + key + ", expectValue=" + expectValue + ", comparisonType=" + comparisonType);

// Validate inputs
if (!validateInputs(key, expectValue, comparisonType)) {
    $runner.setResult(false);
    return;
}

// Lấy giá trị từ session (key có thể là biến <% varName %> hoặc chuỗi có template)
var actualValue = resolveInputValue(key);
var resolvedExpectValue = resolveInputValue(expectValue);

$runner.getLogger().info("[" + $ivr.getRID() + "] [conditional-comparison] actualValue=" + actualValue + " (type: " + typeof actualValue + "), expectValue(resolved)=" + resolvedExpectValue);

// Kiểm tra giá trị có tồn tại trong session
if (actualValue === null || actualValue === undefined) {
    $runner.getLogger().warn("[" + $ivr.getRID() + "] [conditional-comparison] key '" + key + "' not found in session");
    $runner.setResult(false);
    return;
}

// Thực hiện so sánh (expectValue đã được resolve biến/template giống key)
var result = performComparison(actualValue, resolvedExpectValue, comparisonType);

$runner.getLogger().info("[" + $ivr.getRID() + "] [conditional-comparison] Comparison result: " + result);

// Set kết quả
$runner.setResult(result);

var flow = $runner.getProperty("flowname");

// Lấy toàn bộ param string hiện tại
var raw = ivr.getEx().ivr.userinfo.getProperty("ivr.flow.parameter");

// Jump
if (flow) {
    $runner.exec(flow, raw);

    var rid = $ivr.getRID();
    var key = flow + "." + rid;
    var subFlowResult = ivr.getObject(key);
    if (subFlowResult != null && subFlowResult != undefined) {
        $runner.setResult(subFlowResult);
    }
}

// ==================================================================
// 1. 定数定義および市外局番リスト (Area Code List)
// ==================================================================
var logger = $runner.getLogger();

// 市外局番リスト (総務省の番号計画に基づく)
var AREA_2 = ["03", "06"];
var AREA_3 = ["011", "017", "018", "019", "022", "023", "024", "025", "026", "027", "028", "029", "042", "043", "044", "045", "046", "047", "048", "049", "052", "053", "054", "055", "058", "059", "072", "073", "075", "076", "077", "078", "079", "082", "083", "084", "086", "087", "088", "089", "092", "093", "095", "096", "097", "098", "099"];
var AREA_4 = ["0123", "0126", "0134", "0138", "0143", "0144", "0154", "0155", "0157", "0166", "0172", "0176", "0178", "0185", "0186", "0191", "0193", "0197", "0198", "0225", "0226", "0229", "0234", "0235", "0238", "0242", "0246", "0248", "0254", "0256", "0257", "0258", "0263", "0265", "0266", "0267", "0268", "0270", "0274", "0276", "0277", "0280", "0282", "0283", "0284", "0285", "0289", "0294", "0296", "0297", "0299", "0422", "0428", "0436", "0438", "0439", "0463", "0465", "0466", "0467", "0470", "0475", "0476", "0479", "0480", "0493", "0494", "0495", "0532", "0533", "0537", "0538", "0544", "0545", "0547", "0550", "0555", "0557", "0558", "0561", "0562", "0563", "0564", "0565", "0566", "0568", "0569", "0572", "0574", "0575", "0577", "0584", "0586", "0587", "0594", "0595", "0596", "0598", "0721", "0725", "0739", "0742", "0743", "0744", "0745", "0748", "0749", "0761", "0766", "0770", "0771", "0773", "0774", "0776", "0778", "0794", "0797", "0798", "0823", "0827", "0833", "0834", "0835", "0836", "0848", "0852", "0853", "0857", "0859", "0863", "0865", "0868", "0877", "0884", "0895", "0897", "0898", "0930", "0940", "0942", "0944", "0947", "0948", "0949", "0955", "0956", "0957", "0965", "0968", "0972", "0973", "0977", "0979", "0982", "0985", "0986", "0994", "0996"];
var AREA_5 = ["04992", "04994", "01456", "01457", "01632", "01634", "01635"];

// ==================================================================
// 2. ユーティリティ関数 (Utility Functions)
// ==================================================================

/**
 * 日本の電話番号形式にハイフンを挿入する
 * @param {string} digits 数字のみの文字列
 * @return {string} ハイフン付きの番号
 */
function formatJapanesePhone(digits) {
    var d = String(digits).replace(/^\+81/, "0").replace(/\D/g, "");
    var len = d.length;

    if (len === 11) {
        return d.substring(0, 3) + "-" + d.substring(3, 7) + "-" + d.substring(7);
    } 

    if (len === 10) {
        var p5 = d.substring(0, 5);
        var p4 = d.substring(0, 4);
        var p3 = d.substring(0, 3);
        var p2 = d.substring(0, 2);

        if (AREA_5.indexOf(p5) !== -1) return p5 + "-" + d.substring(5, 6) + "-" + d.substring(6);
        if (AREA_4.indexOf(p4) !== -1) return p4 + "-" + d.substring(4, 6) + "-" + d.substring(6);
        if (AREA_3.indexOf(p3) !== -1) return p3 + "-" + d.substring(3, 6) + "-" + d.substring(6);
        if (AREA_2.indexOf(p2) !== -1) return p2 + "-" + d.substring(2, 6) + "-" + d.substring(6);
        
        return d.substring(0, 3) + "-" + d.substring(3, 6) + "-" + d.substring(6);
    }
    return d;
}

/**
 * 読み上げ用に数字の間にスペースを挿入する (AmiVoice 1文字読み対策)
 * @param {string} dStr 数字文字列
 * @return {string} スペース区切りの文字列
 */
function toSpacedDigits(dStr) {
    if (!dStr) return "";
    return dStr.split("").join(" ");
}

/**
 * 設定されたモード(phoneReadingMode)に基づいて確認用数値を生成する
 * @param {string} digits 数字のみの文字列
 * @return {string} 整形済み文字列
 */
function getPhoneConfirmValue(digits) {
    var mode = $runner.getProperty("phoneReadingMode"); // 全桁 or 下4桁

    if (mode === "下4桁") {
        var last4 = digits.slice(-4);
        return toSpacedDigits(last4); // 例: "1 2 3 4"
    } 
    
    // デフォルトは全桁表示
    return formatJapanesePhone(digits); // 例: "090-1234-5678"
}

// ==================================================================
// 3. メイン実行ブロック (Main Execution)
// ==================================================================

// モジュール結果(STT/DTMF)の取得
var moduleName = $runner.getProperty("module");
var moduleRes = $runner.getModuleResult(moduleName);
var moduleDigits = moduleRes ? String(moduleRes).replace(/\D/g, "") : "";

/**
 * [CASE A] モジュール出力がある場合 (STT/DTMF優先)
 * setResult でフル整形番号を返し、後続の確認ノードで使用する。
 */
if (moduleDigits.length >= 10) {
    var finalResult = formatJapanesePhone(moduleDigits);
    
    // 携帯電話(11桁)のバリデーションチェック
    var mPre = moduleDigits.substring(0, 3);
    var isMobile = ["090", "080", "070", "060", "050"].indexOf(mPre) !== -1;
    if (isMobile && moduleDigits.length !== 11) {
        finalResult = "INVALID";
    }

    $runner.setResult(finalResult);
    logger.info("[PhoneProcess] Module Result Flow: " + finalResult);
} 
/**
 * [CASE B] モジュール出力がない場合 (着信番号処理)
 * incomingPhoneプロパティまたはIVR取得番号をDB保存し、読み上げ用Objectをセットする。
 */
else {
    var incomingRaw = $runner.getProperty(".incomingPhone") || $ivr.getOtherNumber();
    var incomingDigits = String(incomingRaw).replace(/^\+81/, "0").replace(/\D/g, "");

    if (incomingDigits) {
        // 1. Context保存 (フル番号をデータベースへ)
        try {
            var contextField = {
                contextName: "additionalPhoneNumber",
                displayType: "PHONE_NUMBER",
                value: incomingDigits
            };
            $ivr.exec("save2db", "save", JSON.stringify({ contextField: contextField }));
            logger.info("[PhoneProcess] Incoming Flow: DB Context Saved (" + incomingDigits + ")");
        } catch (e) {
            logger.error("[PhoneProcess] DB Save Error: " + e);
        }

        // 2. 読み上げ用Objectの生成 (phoneReadingModeに基づく)
        // ※下4桁モードの場合はスペース区切りになり、AmiVoiceが1文字ずつ読み上げる。
        var displayValue = getPhoneConfirmValue(incomingDigits);

        // プロンプト内で <%incoming_phone%> として使用可能
        $runner.setObject("incoming_phone", displayValue);
        
        $runner.setResult("INCOMING_PROCESSED");
        logger.info("[PhoneProcess] Incoming Flow Display: " + displayValue);
    }
}
